h_trail_brute_force   = plot(tx_brute_force_per_frame(1), ty_brute_force_per_frame(1), '-', ... %[output:9d89afbd]
                     'Color', [1 0 0 0.4], 'LineWidth', 1.2); %[output:9d89afbd]
% Past optimum markers (dim red)
h_past_brute_force    = plot(tx_brute_force_per_frame(1), ty_brute_force_per_frame(1), 'rx', ... %[output:9d89afbd]
                     'MarkerSize', 8, 'LineWidth', 1.0, ... %[output:9d89afbd]
                     'Color', [1 0.6 0.6]); %[output:9d89afbd]
% Current optimum (bright red)
h_opt_brute_force         = plot(tx_brute_force_per_frame(1), ty_brute_force_per_frame(1), 'rx', ... %[output:9d89afbd]
                     'MarkerSize', 16, 'LineWidth', 2.5); %[output:9d89afbd]

xlabel('$n_{\psi_x}$','Interpreter','latex'); %[output:9d89afbd]
